import { useState, useEffect } from 'react';
import axios from 'axios';
import RequestTimeline from '../components/RequestTimeline';

const AcademicRequests = () => {
    const [requests, setRequests] = useState([]);
    const [requestType, setRequestType] = useState('');
    const [description, setDescription] = useState('');
    const [message, setMessage] = useState('');
    const [selectedRequestId, setSelectedRequestId] = useState(null);
    const [activeTab, setActiveTab] = useState('active'); // active | archived
    
    const [studentSemester, setStudentSemester] = useState(1);

    const fetchRequests = async () => {
        try {
            const token = localStorage.getItem('token');
            const isArchived = activeTab === 'archived';
            const res = await axios.get(`http://localhost:5000/api/requests/my-requests?archived=${isArchived}`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setRequests(res.data);
        } catch (err) {
            console.error('Error fetching requests:', err);
        }
    };

    const fetchStudentProfile = async () => {
        try {
            const token = localStorage.getItem('token');
            const res = await axios.get('http://localhost:5000/api/users/me', {
                headers: { Authorization: `Bearer ${token}` }
            });
            if (res.data && res.data.semester) {
                setStudentSemester(parseInt(res.data.semester, 10));
            }
        } catch (err) {
            console.error('Error fetching user profile:', err);
        }
    };

    const getStatusBadge = (status) => {
        switch (status) {
            case 'Submitted': return 'bg-yellow-100 text-yellow-800';
            case 'Faculty Approved': return 'bg-blue-100 text-blue-800';
            case 'Approved': return 'bg-green-100 text-green-800';
            case 'Rejected': return 'bg-red-100 text-red-800';
            default: return 'bg-gray-100 text-gray-800';
        }
    };

    useEffect(() => {
        fetchStudentProfile();
        fetchRequests();
    }, [activeTab]);

    const [startDate, setStartDate] = useState('');
    const [endDate, setEndDate] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        setMessage('');
        try {
            const token = localStorage.getItem('token');
            const payload = { requestType, description };

            if (requestType === 'Leave Application') {
                payload.startDate = startDate;
                payload.endDate = endDate;
            }

            await axios.post('http://localhost:5000/api/requests/create',
                payload,
                { headers: { Authorization: `Bearer ${token}` } }
            );
            setMessage('Request submitted successfully!');
            setRequestType('');
            setDescription('');
            setStartDate('');
            setEndDate('');
            fetchRequests();
            if (activeTab !== 'active') setActiveTab('active');
        } catch (err) {
            setMessage(err.response?.data?.message || 'Error submitting request');
            console.error(err);
        }
    };

    // Calculate Available Dropdown Options Based on Semester
    const getAvailableRequestTypes = () => {
        const types = [
            { name: 'Bonafide Certificate', minSemester: 1 },
            { name: 'Leave Application', minSemester: 1 },
            { name: 'Attendance Correction Request', minSemester: 1 },
            { name: 'Re-evaluation Request', minSemester: 1 },
            { name: 'ID Card Replacement', minSemester: 1 },
            { name: 'Subject Change Request', minSemester: 3 },
            { name: 'Internship Approval', minSemester: 4 },
            { name: 'Project Topic Approval', minSemester: 4 },
            { name: 'Project Supervisor Change Request', minSemester: 4 },
            { name: 'Project Extension Request', minSemester: 4 },
        ];
        return types.filter(type => studentSemester >= type.minSemester);
    };

    return (
        <div className="p-6 max-w-7xl mx-auto">
            <h1 className="text-3xl font-bold mb-8 text-gray-800">Academic Requests</h1>

            {/* Tabs */}
            <div className="flex space-x-4 mb-6 border-b border-gray-200">
                <button
                    onClick={() => setActiveTab('active')}
                    className={`pb-2 px-4 font-medium transition-colors relative ${activeTab === 'active'
                        ? 'text-blue-600 border-b-2 border-blue-600'
                        : 'text-gray-500 hover:text-gray-700'
                        }`}
                >
                    Active Requests
                </button>
                <button
                    onClick={() => setActiveTab('archived')}
                    className={`pb-2 px-4 font-medium transition-colors relative ${activeTab === 'archived'
                        ? 'text-blue-600 border-b-2 border-blue-600'
                        : 'text-gray-500 hover:text-gray-700'
                        }`}
                >
                    Archived History
                </button>
            </div>

            {/* If Active Tab, show Create Form */}
            {activeTab === 'active' && (
                <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 mb-8">
                    <h2 className="text-xl font-semibold mb-4 text-gray-800">Submit New Request</h2>
                    {message && (
                        <div className={`p-4 rounded-lg mb-4 ${message.includes('success') ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                            {message}
                        </div>
                    )}
                    <form onSubmit={handleSubmit} className="space-y-4">
                        <div>
                            <label className="block mb-1 font-medium text-gray-700">Request Type</label>
                            <select
                                value={requestType}
                                onChange={(e) => setRequestType(e.target.value)}
                                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-gray-900 bg-white"
                                required
                            >
                                <option value="" disabled>-- Select Academic Request Type --</option>
                                {getAvailableRequestTypes().map((type, index) => (
                                    <option key={index} value={type.name}>{type.name}</option>
                                ))}
                            </select>
                        </div>

                        {/* Conditional Date Inputs for Leave */}
                        {requestType === 'Leave Application' && (
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="block mb-1 font-medium text-gray-700">Start Date</label>
                                    <input
                                        type="date"
                                        value={startDate}
                                        onChange={(e) => setStartDate(e.target.value)}
                                        className="w-full p-3 border border-gray-300 rounded-lg text-gray-900 bg-white focus:ring-2 focus:ring-blue-500 outline-none"
                                        required
                                    />
                                </div>
                                <div>
                                    <label className="block mb-1 font-medium text-gray-700">End Date</label>
                                    <input
                                        type="date"
                                        value={endDate}
                                        onChange={(e) => setEndDate(e.target.value)}
                                        className="w-full p-3 border border-gray-300 rounded-lg text-gray-900 bg-white focus:ring-2 focus:ring-blue-500 outline-none"
                                        required
                                    />
                                </div>
                            </div>
                        )}

                        <div>
                            <label className="block mb-1 font-medium text-gray-700">Description / Reason</label>
                            <textarea
                                placeholder="Enter the reason for your academic request..."
                                value={description}
                                onChange={(e) => setDescription(e.target.value)}
                                className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none h-32 resize-none text-gray-900 bg-white"
                                required
                            ></textarea>
                        </div>
                        <button type="submit" className="bg-blue-600 text-white px-6 py-3 rounded-lg hover:bg-blue-700 font-medium transition-colors shadow-sm">
                            Submit Request
                        </button>
                    </form>
                </div>
            )}

            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                <h3 className="text-xl font-semibold mb-6 text-gray-800">
                    {activeTab === 'active' ? 'My Active Requests' : 'Request History'}
                </h3>
                {requests.length === 0 ? (
                    <div className="text-center py-8 text-gray-500">
                        {activeTab === 'active' ? 'No active requests.' : 'No archived history.'}
                    </div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="border-b border-gray-100 bg-gray-50">
                                    <th className="p-4 font-semibold text-gray-600 uppercase text-xs">Request ID</th>
                                    <th className="p-4 font-semibold text-gray-600 uppercase text-xs">Type</th>
                                    <th className="p-4 font-semibold text-gray-600 uppercase text-xs">Status</th>
                                    <th className="p-4 font-semibold text-gray-600 uppercase text-xs">Remarks</th>
                                    <th className="p-4 font-semibold text-gray-600 uppercase text-xs">Submitted Date</th>
                                    <th className="p-4 font-semibold text-gray-600 uppercase text-xs">Action</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100">
                                {requests.map((req) => (
                                    <tr key={req.requestId} className="hover:bg-gray-50 transition-colors">
                                        <td className="p-4 font-mono text-sm text-gray-700">{req.requestId}</td>
                                        <td className="p-4 font-medium text-gray-800">{req.requestType}</td>
                                        <td className="p-4">
                                            <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide ${getStatusBadge(req.status)}`}>
                                                {req.status}
                                            </span>
                                        </td>
                                        <td className="p-4 text-sm text-gray-600 max-w-xs truncate">
                                            {req.adminRemarks || req.facultyRemarks || '-'}
                                        </td>
                                        <td className="p-4 text-sm text-gray-600">{new Date(req.createdAt).toLocaleDateString()}</td>
                                        <td className="p-4">
                                            <button
                                                onClick={() => setSelectedRequestId(req.requestId)}
                                                className="text-blue-600 hover:text-blue-800 underline text-sm font-medium"
                                            >
                                                View Timeline
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            {selectedRequestId && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
                    <RequestTimeline
                        requestId={selectedRequestId}
                        onClose={() => setSelectedRequestId(null)}
                    />
                </div>
            )}
        </div>
    );
};

export default AcademicRequests;

