import { useState, useEffect } from 'react';
import axios from 'axios';
import RequestTimeline from '../components/RequestTimeline';

const AdminRequests = () => {
    const [requests, setRequests] = useState([]);
    const [message, setMessage] = useState('');
    // State to track remarks and active action for each request
    const [actionState, setActionState] = useState({});
    const [selectedRequestId, setSelectedRequestId] = useState(null);
    const [activeTab, setActiveTab] = useState('pending'); // 'pending' (Active) or 'history' (Archived)
    const [showDelayedOnly, setShowDelayedOnly] = useState(false);

    const fetchRequests = async () => {
        try {
            const token = localStorage.getItem('token');
            const isArchived = activeTab === 'history';
            // Use unified endpoint
            const url = `http://localhost:5000/api/requests/admin/all?archived=${isArchived}`;

            const res = await axios.get(url, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setRequests(res.data);
        } catch (err) {
            console.error('Error fetching admin requests:', err);
        }
    };

    useEffect(() => {
        fetchRequests();
    }, [activeTab]);

    const handleAction = async (requestId, status) => {
        const remarks = actionState[requestId]?.remarks;

        if (!remarks) {
            setMessage(`Error: Remarks are mandatory to ${status} request.`);
            return;
        }

        try {
            const token = localStorage.getItem('token');
            await axios.put(`http://localhost:5000/api/requests/admin/${requestId}/status`,
                { status, remarks },
                { headers: { Authorization: `Bearer ${token}` } }
            );

            setMessage(`Request ${status} successfully!`);
            // Clear remarks for this request locally, though it will vanish from list
            setActionState({ ...actionState, [requestId]: { remarks: '' } });
            fetchRequests();
        } catch (err) {
            console.error('Error updating status:', err);
            setMessage('Error updating status. Please try again.');
        }
    };

    const handleRemarkChange = (requestId, value) => {
        setActionState({
            ...actionState,
            [requestId]: { ...actionState[requestId], remarks: value }
        });
    };

    const filteredRequests = showDelayedOnly
        ? requests.filter(r => r.isFacultyDelayed || r.isAdminDelayed)
        : requests;

    return (
        <div className="p-6 max-w-6xl mx-auto">
            <h2 className="text-2xl font-bold mb-6">Manage Academic Requests</h2>

            {message && <div className="mb-4 p-3 bg-blue-100 text-blue-800 rounded">{message}</div>}

            <div className="flex justify-between items-end mb-4">
                <div className="flex">
                    <button
                        className={`px-4 py-2 font-semibold rounded-t-lg ${activeTab === 'pending' ? 'bg-white text-blue-600 border-t-2 border-blue-600' : 'bg-gray-100 text-gray-600'}`}
                        onClick={() => setActiveTab('pending')}
                    >
                        Pending Approval
                    </button>
                    <button
                        className={`px-4 py-2 font-semibold rounded-t-lg ${activeTab === 'history' ? 'bg-white text-blue-600 border-t-2 border-blue-600' : 'bg-gray-100 text-gray-600'}`}
                        onClick={() => setActiveTab('history')}
                    >
                        All Request History
                    </button>
                </div>

                <label className="flex items-center space-x-2 bg-white px-3 py-2 rounded shadow-sm text-sm border cursor-pointer hover:bg-gray-50">
                    <input
                        type="checkbox"
                        checked={showDelayedOnly}
                        onChange={(e) => setShowDelayedOnly(e.target.checked)}
                        className="rounded text-blue-600 focus:ring-blue-500"
                    />
                    <span className="font-medium text-gray-700">Show Delayed Only</span>
                </label>
            </div>

            <div className="bg-white p-6 rounded shadow text-gray-900">
                <h3 className="text-xl font-semibold mb-6">
                    {activeTab === 'pending' ? 'Pending Final Approval' : 'Historical Record of All Requests'}
                </h3>
                {filteredRequests.length === 0 ? (
                    <div className="text-center py-8 text-gray-500">
                        {showDelayedOnly
                            ? 'No delayed requests found.'
                            : (activeTab === 'pending' ? 'No requests pending.' : 'No history found.')}
                    </div>
                ) : (
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="border-b">
                                <th className="p-4 font-semibold text-gray-600 border-b">Request ID</th>
                                <th className="p-4 font-semibold text-gray-600 border-b">Student</th>
                                <th className="p-4 font-semibold text-gray-600 border-b">Type</th>
                                <th className="p-4 font-semibold text-gray-600 border-b">Faculty Remarks</th>
                                <th className="p-4 font-semibold text-gray-600 border-b">
                                    {activeTab === 'pending' ? 'Your Remarks (Mandatory)' : 'Status / Remarks'}
                                </th>
                                <th className="p-4 font-semibold text-gray-600 border-b">Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filteredRequests.map((req) => (
                                <tr key={req.requestId} className="border-b hover:bg-gray-50 transition-colors">
                                    <td className="p-4">
                                        {req.requestId}
                                        <button
                                            onClick={() => setSelectedRequestId(req.requestId)}
                                            className="block mt-2 text-blue-600 hover:text-blue-800 underline text-xs"
                                        >
                                            View Timeline
                                        </button>

                                        {/* Delay Indicators */}
                                        <div className="mt-2 space-y-1">
                                            {req.isFacultyDelayed && (
                                                <span className="block px-2 py-0.5 bg-red-100 text-red-800 text-[10px] font-bold rounded border border-red-200">
                                                    ⚠ Faculty Delayed
                                                </span>
                                            )}
                                            {req.isAdminDelayed && (
                                                <span className="block px-2 py-0.5 bg-orange-100 text-orange-800 text-[10px] font-bold rounded border border-orange-200">
                                                    ⚠ Admin Delayed
                                                </span>
                                            )}
                                        </div>
                                    </td>
                                    <td className="p-4">
                                        <div className="font-medium">{req.studentId?.name}</div>
                                        <div className="text-sm text-gray-500">{req.studentId?.loginId}</div>
                                    </td>
                                    <td className="p-4">
                                        <div className="font-medium">{req.requestType}</div>
                                        <div className="text-sm text-gray-500 truncate max-w-xs" title={req.description}>{req.description}</div>
                                    </td>
                                    <td className="p-4 text-sm text-gray-600 italic">"{req.facultyRemarks}"</td>
                                    <td className="p-4">
                                        {activeTab === 'pending' ? (
                                            <textarea
                                                className="w-full p-2 border rounded text-sm"
                                                placeholder="Enter final remarks..."
                                                rows="2"
                                                value={actionState[req.requestId]?.remarks || ''}
                                                onChange={(e) => handleRemarkChange(req.requestId, e.target.value)}
                                            ></textarea>
                                        ) : (
                                            <div>
                                                <div className="font-bold text-sm">{req.status}</div>
                                                <div className="text-xs text-gray-500">
                                                    {req.adminRemarks ? (
                                                        `Admin: "${req.adminRemarks}"`
                                                    ) : req.status === 'Rejected' && !req.adminActionDate ? (
                                                        <span className="text-red-600 font-medium">Faculty Rejected Request</span>
                                                    ) : (
                                                        'Pending Admin Action'
                                                    )}
                                                </div>
                                            </div>
                                        )}
                                    </td>
                                    <td className="p-4 space-x-2 min-w-[150px]">
                                        {activeTab === 'pending' ? (
                                            <>
                                                <button
                                                    onClick={() => handleAction(req.requestId, 'Approved')}
                                                    className="bg-green-600 text-white px-3 py-1 rounded text-sm hover:bg-green-700 w-full mb-1"
                                                >
                                                    Approve
                                                </button>
                                                <button
                                                    onClick={() => handleAction(req.requestId, 'Rejected')}
                                                    className="bg-red-600 text-white px-3 py-1 rounded text-sm hover:bg-red-700 w-full"
                                                >
                                                    Reject
                                                </button>
                                            </>
                                        ) : (
                                            <span className="text-gray-400 text-sm italic">Read Only</span>
                                        )}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                )}
            </div>

            {selectedRequestId && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
                    <RequestTimeline
                        requestId={selectedRequestId}
                        onClose={() => setSelectedRequestId(null)}
                    />
                </div>
            )}
        </div>
    );
};


export default AdminRequests;

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Save, Lock, User, AlertCircle, CheckCircle } from 'lucide-react';

const AssessmentMarksEntry = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const token = localStorage.getItem('token');

    const [assessment, setAssessment] = useState(null);
    const [students, setStudents] = useState([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        fetchDetails();
    }, [id]);

    const fetchDetails = async () => {
        try {
            const res = await axios.get(`http://localhost:5000/api/assessments/${id}`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setAssessment(res.data.assessment);
            setStudents(res.data.students);
        } catch (err) {
            console.error(err);
            alert('Error loading assessment details');
            navigate('/faculty/assessments');
        } finally {
            setLoading(false);
        }
    };

    const handleMarkChange = (studentId, value) => {
        // Allow empty string to clear
        if (value === '') {
            updateStudentMark(studentId, '');
            return;
        }

        const numVal = parseFloat(value);
        if (isNaN(numVal)) return;
        if (numVal < 0) return; // Prevent negative
        // Allow > maxMarks temporarily but show warning? Or strictly block? 
        // Plan said "Validation: Marks <= Max Marks". Let's block here or validate on save.
        // It's better UX to validate on blur or save, but blocking extreme values is ok.

        updateStudentMark(studentId, numVal);
    };

    const updateStudentMark = (studentId, val) => {
        setStudents(prev => prev.map(s =>
            s._id === studentId ? { ...s, marksObtained: val } : s
        ));
    };

    const handleSave = async () => {
        setSaving(true);
        try {
            // Filter only filled marks or send all? Send all where marksObtained is not empty or null.
            // Wait, checks logic said send all marksData.

            const records = students
                .filter(s => s.marksObtained !== '' && s.marksObtained !== null && s.marksObtained !== undefined)
                .map(s => ({
                    studentId: s._id,
                    marksObtained: s.marksObtained
                }));

            // Validate Frontend Side too
            for (let r of records) {
                if (r.marksObtained > assessment.maxMarks) {
                    alert(`Error: Marks for some students exceed max marks (${assessment.maxMarks})`);
                    setSaving(false);
                    return;
                }
            }

            await axios.post(`http://localhost:5000/api/assessments/${id}/marks`,
                { marksData: records },
                { headers: { Authorization: `Bearer ${token}` } }
            );

            alert('Marks saved successfully!');
            fetchDetails(); // Refresh
        } catch (err) {
            console.error(err);
            alert(err.response?.data?.message || 'Error saving marks');
        } finally {
            setSaving(false);
        }
    };

    if (loading) return <div className="flex justify-center py-20 text-white">Loading...</div>;
    if (!assessment) return <div className="text-center text-white py-20">Assessment not found</div>;

    const isLocked = assessment.status === 'Locked';

    return (
        <div className="p-6 max-w-5xl mx-auto min-h-screen">
            <button
                onClick={() => navigate('/faculty/assessments')}
                className="flex items-center gap-2 text-gray-400 hover:text-white transition-colors mb-6"
            >
                <ArrowLeft size={20} /> Back to Assessments
            </button>

            <div className="bg-gray-800 rounded-2xl shadow-xl overflow-hidden border border-gray-700">
                <div className="p-6 border-b border-gray-700 bg-gray-900/50 flex flex-col md:flex-row justify-between md:items-center gap-4">
                    <div>
                        <div className="flex items-center gap-2 mb-1">
                            {isLocked && <span className="bg-red-500/20 text-red-500 text-xs font-bold px-2 py-0.5 rounded flex items-center gap-1"><Lock size={10} /> LOCKED</span>}
                            <span className="text-blue-400 font-mono text-sm">{assessment.type}</span>
                        </div>
                        <h2 className="text-2xl font-bold text-white">{assessment.title}</h2>
                        <p className="text-gray-400 text-sm mt-1">
                            {assessment.subjectId?.name} ({assessment.subjectId?.code}) • Max Marks: <span className="text-white font-bold">{assessment.maxMarks}</span>
                        </p>
                    </div>

                    {!isLocked && (
                        <button
                            onClick={handleSave}
                            disabled={saving}
                            className={`flex items-center gap-2 bg-green-600 hover:bg-green-700 text-white px-6 py-2.5 rounded-xl font-bold shadow-lg shadow-green-500/20 transition-all ${saving ? 'opacity-70 cursor-not-allowed' : ''}`}
                        >
                            {saving ? 'Saving...' : <><Save size={20} /> Save Marks</>}
                        </button>
                    )}
                </div>

                <div className="max-h-[70vh] overflow-y-auto">
                    <table className="w-full text-left">
                        <thead className="bg-gray-900/80 sticky top-0 backdrop-blur-sm z-10">
                            <tr>
                                <th className="p-4 text-gray-400 font-medium border-b border-gray-700">Student Name</th>
                                <th className="p-4 text-gray-400 font-medium border-b border-gray-700">Roll No / Login ID</th>
                                <th className="p-4 text-gray-400 font-medium border-b border-gray-700 w-48 text-right">Marks Obtained</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-700">
                            {students.map((student) => (
                                <tr key={student._id} className="hover:bg-gray-700/30 transition-colors group">
                                    <td className="p-4 text-white font-medium group-hover:text-blue-200 transition-colors">
                                        <div className="flex items-center gap-3">
                                            <div className="w-8 h-8 rounded-full bg-gray-700 flex items-center justify-center text-gray-400">
                                                <User size={14} />
                                            </div>
                                            {student.name}
                                        </div>
                                    </td>
                                    <td className="p-4 text-gray-500 font-mono text-sm">{student.loginId}</td>
                                    <td className="p-4 text-right">
                                        <div className="flex items-center justify-end gap-2">
                                            <input
                                                type="number"
                                                className={`w-24 bg-gray-900 border ${student.marksObtained > assessment.maxMarks ? 'border-red-500 focus:ring-red-500' : 'border-gray-600 focus:ring-blue-500'} rounded-lg px-3 py-2 text-right text-white font-mono focus:ring-2 focus:border-transparent outline-none transition-all disabled:opacity-50 disabled:cursor-not-allowed`}
                                                value={student.marksObtained}
                                                onChange={(e) => handleMarkChange(student._id, e.target.value)}
                                                disabled={isLocked}
                                                placeholder="-"
                                            />
                                            <span className="text-gray-500 font-mono text-sm">/ {assessment.maxMarks}</span>
                                        </div>
                                        {student.marksObtained > assessment.maxMarks && (
                                            <p className="text-red-400 text-xs mt-1 text-right">Exceeds Max Marks</p>
                                        )}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>

                <div className="p-4 bg-gray-900/30 border-t border-gray-700 text-center text-gray-500 text-xs">
                    {students.length} students enrolled • {students.filter(s => s.marksObtained !== '' && s.marksObtained !== undefined).length} marks entered
                </div>
            </div>
        </div>
    );
};

export default AssessmentMarksEntry;

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Plus, BookOpen, Lock, Edit2, ChevronRight, AlertCircle, CheckCircle, FileText } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const FacultyAssessments = () => {
    const [assessments, setAssessments] = useState([]);
    const [subjects, setSubjects] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showCreateModal, setShowCreateModal] = useState(false);
    const navigate = useNavigate();
    const token = localStorage.getItem('token');

    // Form State
    const [newItem, setNewItem] = useState({
        subjectId: '',
        type: 'Test',
        title: '',
        maxMarks: 100
    });

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setLoading(true);
        try {
            const [assessmentsRes, subjectsRes] = await Promise.all([
                axios.get('http://localhost:5000/api/assessments/faculty/list', { headers: { Authorization: `Bearer ${token}` } }),
                axios.get('http://localhost:5000/api/subjects/faculty/subjects', { headers: { Authorization: `Bearer ${token}` } })
            ]);
            setAssessments(assessmentsRes.data);
            setSubjects(subjectsRes.data);
            if (subjectsRes.data.length > 0) {
                setNewItem(prev => ({ ...prev, subjectId: subjectsRes.data[0]._id }));
            }
        } catch (err) {
            console.error(err);
            // alert('Error loading data');
        } finally {
            setLoading(false);
        }
    };

    const handleCreate = async (e) => {
        e.preventDefault();
        try {
            await axios.post('http://localhost:5000/api/assessments/create', newItem, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setShowCreateModal(false);
            fetchData();
            // Reset form (keep subjectId)
            setNewItem(prev => ({ ...prev, title: '', maxMarks: 100 }));
            alert('Assessment created successfully!');
        } catch (err) {
            alert(err.response?.data?.message || 'Error creating assessment');
        }
    };

    const handleLock = async (id, title) => {
        if (!window.confirm(`Are you sure you want to LOCK "${title}"? Marks cannot be edited after locking.`)) return;

        try {
            await axios.put(`http://localhost:5000/api/assessments/${id}/lock`, {}, {
                headers: { Authorization: `Bearer ${token}` }
            });
            fetchData();
        } catch (err) {
            alert('Error locking assessment');
        }
    };

    const getStatusRole = (status) => {
        return status === 'Locked'
            ? 'bg-red-500/10 text-red-500 border border-red-500/20'
            : 'bg-green-500/10 text-green-500 border border-green-500/20';
    };

    return (
        <div className="p-6 max-w-7xl mx-auto min-h-screen">
            <header className="flex justify-between items-center mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-white flex items-center gap-3">
                        <FileText className="text-blue-500" size={32} />
                        Assessments
                    </h1>
                    <p className="text-gray-400 mt-1">Manage tests, quizzes, and marks.</p>
                </div>
                <button
                    onClick={() => setShowCreateModal(true)}
                    className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 rounded-xl font-bold flex items-center gap-2 transition-all shadow-lg shadow-blue-500/20"
                >
                    <Plus size={20} /> Create Assessment
                </button>
            </header>

            {loading ? (
                <div className="flex justify-center py-20"><div className="animate-spin w-10 h-10 border-4 border-blue-500 border-t-transparent rounded-full"></div></div>
            ) : assessments.length === 0 ? (
                <div className="text-center py-20 bg-gray-800/50 rounded-2xl border border-gray-700 border-dashed">
                    <div className="bg-gray-800 p-4 rounded-full inline-block mb-4">
                        <FileText size={40} className="text-gray-600" />
                    </div>
                    <h3 className="text-xl font-bold text-white mb-2">No Assessments Created</h3>
                    <p className="text-gray-400">Click the button above to create one.</p>
                </div>
            ) : (
                <div className="grid gap-6">
                    {assessments.map((item) => (
                        <div key={item._id} className="bg-gray-800 rounded-xl p-6 border border-gray-700 flex flex-col md:flex-row items-start md:items-center justify-between gap-6 hover:border-gray-600 transition-colors">
                            <div className="flex-1">
                                <div className="flex items-center gap-3 mb-2">
                                    <span className={`text-xs font-bold px-2 py-0.5 rounded uppercase tracking-wider ${getStatusRole(item.status)}`}>
                                        {item.status}
                                    </span>
                                    <span className="text-xs font-mono text-gray-500 bg-gray-700/50 px-2 py-0.5 rounded">
                                        {item.type}
                                    </span>
                                </div>
                                <h3 className="text-xl font-bold text-white mb-1">{item.title}</h3>
                                <div className="flex items-center gap-4 text-sm text-gray-400">
                                    <span className="flex items-center gap-1.5"><BookOpen size={14} /> {item.subjectId?.name} ({item.subjectId?.code})</span>
                                    <span>•</span>
                                    <span>Max Marks: {item.maxMarks}</span>
                                    <span>•</span>
                                    <span>{new Date(item.createdAt).toLocaleDateString()}</span>
                                </div>
                            </div>

                            <div className="flex items-center gap-3 w-full md:w-auto">
                                <button
                                    onClick={() => navigate(`/faculty/assessments/${item._id}`)}
                                    className="flex-1 md:flex-none px-4 py-2 bg-gray-700 hover:bg-gray-600 text-white rounded-lg font-medium transition-colors flex items-center justify-center gap-2"
                                >
                                    {item.status === 'Locked' ? <><BookOpen size={18} /> View Marks</> : <><Edit2 size={18} /> Enter Marks</>}
                                </button>
                                {item.status !== 'Locked' && (
                                    <button
                                        onClick={() => handleLock(item._id, item.title)}
                                        className="px-4 py-2 bg-red-600/10 hover:bg-red-600/20 text-red-500 border border-red-600/30 rounded-lg transition-colors flex items-center justify-center gap-2"
                                        title="Lock Assessment"
                                    >
                                        <Lock size={18} />
                                    </button>
                                )}
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {showCreateModal && (
                <div className="fixed inset-0 bg-black/70 backdrop-blur-sm flex items-center justify-center z-50 p-4">
                    <div className="bg-gray-800 rounded-2xl w-full max-w-md border border-gray-700 shadow-2xl overflow-hidden">
                        <div className="p-6 border-b border-gray-700 flex justify-between items-center bg-gray-900/50">
                            <h3 className="text-xl font-bold text-white">Create Assessment</h3>
                            <button onClick={() => setShowCreateModal(false)} className="text-gray-400 hover:text-white">&times;</button>
                        </div>
                        <form onSubmit={handleCreate} className="p-6 space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-400 mb-1">Subject</label>
                                <select
                                    className="w-full bg-gray-700 border border-gray-600 rounded-lg p-2.5 text-white focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                                    value={newItem.subjectId}
                                    onChange={e => setNewItem({ ...newItem, subjectId: e.target.value })}
                                    required
                                >
                                    {subjects.map(s => <option key={s._id} value={s._id}>{s.name} ({s.code})</option>)}
                                </select>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-400 mb-1">Type</label>
                                <select
                                    className="w-full bg-gray-700 border border-gray-600 rounded-lg p-2.5 text-white focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                                    value={newItem.type}
                                    onChange={e => setNewItem({ ...newItem, type: e.target.value })}
                                >
                                    {['Test', 'Quiz', 'Assignment', 'Mid-Term', 'Final', 'Project'].map(t => <option key={t} value={t}>{t}</option>)}
                                </select>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-400 mb-1">Title</label>
                                <input
                                    type="text"
                                    className="w-full bg-gray-700 border border-gray-600 rounded-lg p-2.5 text-white focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                                    placeholder="e.g., Unit Test 1"
                                    value={newItem.title}
                                    onChange={e => setNewItem({ ...newItem, title: e.target.value })}
                                    required
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-400 mb-1">Max Marks</label>
                                <input
                                    type="number"
                                    className="w-full bg-gray-700 border border-gray-600 rounded-lg p-2.5 text-white focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                                    min="1"
                                    value={newItem.maxMarks}
                                    onChange={e => setNewItem({ ...newItem, maxMarks: parseInt(e.target.value) })}
                                    required
                                />
                            </div>

                            <div className="pt-4 flex gap-3">
                                <button
                                    type="button"
                                    onClick={() => setShowCreateModal(false)}
                                    className="flex-1 py-2.5 bg-gray-700 hover:bg-gray-600 text-white rounded-lg font-medium transition-colors"
                                >
                                    Cancel
                                </button>
                                <button
                                    type="submit"
                                    className="flex-1 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-bold transition-all shadow-lg shadow-blue-500/20"
                                >
                                    Create
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default FacultyAssessments;

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Calendar, Clock, MapPin, CheckCircle, AlertCircle, PlayCircle, Users, ArrowLeft, Save, Shield } from 'lucide-react';

const FacultyAttendance = () => {
    const [schedule, setSchedule] = useState([]);
    const [loading, setLoading] = useState(true);
    const [view, setView] = useState('list'); // 'list' or 'attendance'
    const [activeLecture, setActiveLecture] = useState(null);
    const [activeSessionId, setActiveSessionId] = useState(null);
    const [students, setStudents] = useState([]);
    const [submitting, setSubmitting] = useState(false);

    const token = localStorage.getItem('token');

    useEffect(() => {
        fetchSchedule();
    }, []);

    const fetchSchedule = async () => {
        setLoading(true);
        try {
            const res = await axios.get('http://localhost:5000/api/timetable/faculty/today', {
                headers: { Authorization: `Bearer ${token}` }
            });
            setSchedule(res.data);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const handleMarkAttendance = async (lecture) => {
        // Allow if Upcoming (future) or if Expired but potentially want to mark late? 
        // Actually, requirement is to allow marking if finished (Expired).
        // So we only block if it's strictly 'Upcoming' and we want to enforce time? 
        // Or if it's already submitted (though we might want to edit).

        // Revised logic based on user request: 
        // Allow 'Ongoing', 'Submitted' (to edit), and 'Expired' (to mark late).
        // Disallow 'Upcoming' (too early).

        if (lecture.status === 'Upcoming') {
            alert("Cannot mark attendance for future lectures.");
            return;
        }

        setActiveLecture(lecture);

        try {
            let sessionId = lecture.sessionId;

            // If no session exists yet, create one
            if (!sessionId) {
                const createRes = await axios.post('http://localhost:5000/api/attendance/session/create',
                    {
                        subjectId: lecture.subjectId._id,
                        date: new Date(),
                        timetableId: lecture._id,
                        section: lecture.section // Included section!
                    },
                    { headers: { Authorization: `Bearer ${token}` } }
                );
                sessionId = createRes.data._id;
            }

            setActiveSessionId(sessionId);
            loadSessionData(sessionId, lecture.subjectId._id, lecture.section);
            setView('attendance');

        } catch (err) {
            alert(err.response?.data?.message || 'Error initializing session');
        }
    };

    const loadSessionData = async (sessionId, subjectId, section) => {
        try {
            // Get session details and records
            const sessionRes = await axios.get(`http://localhost:5000/api/attendance/session/${sessionId}`, {
                headers: { Authorization: `Bearer ${token}` }
            });

            const existingRecords = sessionRes.data.records; // [{ studentId, status }]

            // Get all students for the subject and specific section
            const studentsRes = await axios.get(`http://localhost:5000/api/attendance/session/${subjectId}/students?section=${section}`, {
                headers: { Authorization: `Bearer ${token}` }
            });

            // Merge details
            const merged = studentsRes.data.map(student => {
                const record = existingRecords.find(r => r.studentId === student._id);
                return {
                    ...student,
                    status: record ? record.status : 'Present' // Default to Present
                };
            });

            setStudents(merged);
        } catch (err) {
            console.error('loadSessionData ERROR:', err.response || err);
            alert(`Failed to load student list: ${err.response?.data?.message || err.message}`);
        }
    };

    const toggleStatus = (index) => {
        const updated = [...students];
        updated[index].status = updated[index].status === 'Present' ? 'Absent' : 'Present';
        setStudents(updated);
    };

    const submitAttendance = async () => {
        setSubmitting(true);
        try {
            const records = students.map(s => ({
                studentId: s._id,
                status: s.status
            }));

            await axios.post('http://localhost:5000/api/attendance/mark',
                { sessionId: activeSessionId, records },
                { headers: { Authorization: `Bearer ${token}` } }
            );
            alert('Attendance marked successfully! ✅');
            setView('list');
            fetchSchedule(); // Refresh status
        } catch (err) {
            console.error(err);
            alert('Error marking attendance');
        } finally {
            setSubmitting(false);
        }
    };

    // Helper to get status badge styling
    const getStatusStyle = (status) => {
        switch (status) {
            case 'Ongoing': return 'bg-green-100 text-green-700 border-green-200 animate-pulse';
            case 'Upcoming': return 'bg-blue-50 text-blue-600 border-blue-100';
            case 'Submitted': return 'bg-purple-100 text-purple-700 border-purple-200';
            case 'Expired': return 'bg-gray-100 text-gray-500 border-gray-200';
            default: return 'bg-gray-100 text-gray-800';
        }
    };

    if (view === 'attendance') {
        return (
            <div className="p-6 max-w-5xl mx-auto space-y-6">
                <button
                    onClick={() => setView('list')}
                    className="flex items-center gap-2 text-gray-400 hover:text-white transition-colors"
                >
                    <ArrowLeft size={20} /> Back to Schedule
                </button>

                <div className="bg-gray-800 rounded-2xl shadow-xl overflow-hidden border border-gray-700">
                    <div className="p-6 border-b border-gray-700 bg-gray-900/50 flex justify-between items-center">
                        <div>
                            <h2 className="text-xl font-bold text-white flex items-center gap-2">
                                <Users className="text-blue-400" />
                                Marking Attendance
                            </h2>
                            <p className="text-gray-400 text-sm mt-1">
                                {activeLecture?.subjectId?.name} ({activeLecture?.subjectId?.code}) • {activeLecture?.startTime} - {activeLecture?.endTime}
                            </p>
                        </div>
                        <div className="bg-blue-900/30 text-blue-400 px-4 py-2 rounded-lg text-sm font-mono border border-blue-800">
                            {new Date().toLocaleDateString(undefined, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
                        </div>
                    </div>

                    <div className="max-h-[60vh] overflow-y-auto">
                        <table className="w-full text-left">
                            <thead className="bg-gray-900/80 sticky top-0 backdrop-blur-sm z-10">
                                <tr>
                                    <th className="p-4 text-gray-400 font-medium border-b border-gray-700">Student Name</th>
                                    <th className="p-4 text-gray-400 font-medium border-b border-gray-700">Roll No / ID</th>
                                    <th className="p-4 text-gray-400 font-medium border-b border-gray-700 text-center">Status</th>
                                    <th className="p-4 text-gray-400 font-medium border-b border-gray-700 text-right">Action</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-700">
                                {students.map((student, idx) => (
                                    <tr key={student._id} className="hover:bg-gray-700/30 transition-colors group">
                                        <td className="p-4 text-white font-medium group-hover:text-blue-200 transition-colors">{student.name}</td>
                                        <td className="p-4 text-gray-500 font-mono text-sm">{student.loginId}</td>
                                        <td className="p-4 text-center">
                                            <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider ${student.status === 'Present' ? 'bg-green-900/30 text-green-400 border border-green-800 shadow-[0_0_10px_rgba(74,222,128,0.1)]' : 'bg-red-900/30 text-red-400 border border-red-800 shadow-[0_0_10px_rgba(248,113,113,0.1)]'}`}>
                                                {student.status === 'Present' ? <CheckCircle size={12} /> : <AlertCircle size={12} />}
                                                {student.status}
                                            </span>
                                        </td>
                                        <td className="p-4 text-right">
                                            <button
                                                className={`px-4 py-1.5 rounded-lg text-white text-xs font-bold uppercase tracking-wider transition-all transform active:scale-95 shadow-lg ${student.status === 'Present' ? 'bg-red-600 hover:bg-red-700 shadow-red-500/20' : 'bg-green-600 hover:bg-green-700 shadow-green-500/20'}`}
                                                onClick={() => toggleStatus(idx)}
                                            >
                                                Mark {student.status === 'Present' ? 'Absent' : 'Present'}
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>

                    <div className="p-6 border-t border-gray-700 bg-gray-900/50 flex justify-between items-center">
                        <div className="text-gray-400 text-sm">
                            Total Students: <span className="text-white font-bold">{students.length}</span> •
                            Present: <span className="text-green-400 font-bold">{students.filter(s => s.status === 'Present').length}</span> •
                            Absent: <span className="text-red-400 font-bold">{students.filter(s => s.status === 'Absent').length}</span>
                        </div>
                        <button
                            className={`flex items-center gap-2 bg-green-600 text-white px-8 py-3 rounded-xl hover:bg-green-700 font-bold shadow-lg shadow-green-500/30 transition-all transform hover:-translate-y-1 ${submitting ? 'opacity-70 cursor-not-allowed' : ''}`}
                            onClick={submitAttendance}
                            disabled={submitting}
                        >
                            {submitting ? 'Saving...' : <><Save size={20} /> Save Attendance</>}
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="p-6 max-w-7xl mx-auto min-h-screen">
            <header className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold text-white mb-2 flex items-center gap-3">
                        <Calendar className="text-blue-500" size={32} />
                        Today's Schedule
                    </h1>
                    <p className="text-gray-400">
                        {new Date().toLocaleDateString(undefined, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
                    </p>
                </div>
                <div className="bg-gray-800 px-4 py-2 rounded-lg border border-gray-700 flex items-center gap-3 text-sm text-gray-300 shadow-sm">
                    <div className="flex items-center gap-1.5"><span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span> Ongoing</div>
                    <div className="w-px h-4 bg-gray-600"></div>
                    <div className="flex items-center gap-1.5"><span className="w-2 h-2 rounded-full bg-blue-400"></span> Upcoming</div>
                    <div className="w-px h-4 bg-gray-600"></div>
                    <div className="flex items-center gap-1.5"><span className="w-2 h-2 rounded-full bg-purple-400"></span> Submitted</div>
                </div>
            </header>

            {loading ? (
                <div className="flex flex-col items-center justify-center py-20 text-gray-500">
                    <div className="w-12 h-12 border-4 border-blue-500/30 border-t-blue-500 rounded-full animate-spin mb-4"></div>
                    <p>Loading today's sessions...</p>
                </div>
            ) : schedule.length === 0 ? (
                <div className="text-center py-20 bg-gray-800/50 rounded-2xl border border-gray-700 border-dashed">
                    <div className="bg-gray-800 p-4 rounded-full inline-block mb-4 shadow-inner">
                        <Calendar size={40} className="text-gray-600" />
                    </div>
                    <h3 className="text-xl font-bold text-white mb-2">No Lectures Scheduled Today</h3>
                    <p className="text-gray-400">Enjoy your free time!</p>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {schedule.map((item, idx) => (
                        <div key={idx} className={`relative bg-gray-800 rounded-2xl p-6 border transition-all duration-300 hover:shadow-2xl hover:-translate-y-1 group ${item.status === 'Ongoing' ? 'border-green-500/50 shadow-green-500/10 ring-1 ring-green-500/30' : 'border-gray-700 shadow-lg'}`}>

                            <div className="flex justify-between items-start mb-6">
                                <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider border ${getStatusStyle(item.status)}`}>
                                    {item.status}
                                </span>
                                <span className="text-gray-500 font-mono text-xs flex items-center gap-1">
                                    <Clock size={12} />
                                    {item.endTime}
                                </span>
                            </div>

                            <div className="mb-6">
                                <h3 className="text-xl font-bold text-white mb-1 group-hover:text-blue-400 transition-colors line-clamp-1" title={item.subjectId?.name}>
                                    {item.subjectId?.name}
                                </h3>
                                <div className="flex items-center gap-2 text-sm text-gray-400 mb-4">
                                    <span className="bg-gray-700/50 px-2 py-0.5 rounded text-xs font-mono text-gray-300">{item.subjectId?.code}</span>
                                    <span>•</span>
                                    <span>Semester {item.semester}</span>
                                </div>

                                <div className="flex items-center gap-3 text-gray-300 bg-gray-700/30 p-3 rounded-xl border border-gray-700/50">
                                    <div className="bg-blue-500/10 p-2 rounded-lg text-blue-400">
                                        <Clock size={20} />
                                    </div>
                                    <div>
                                        <div className="text-xs text-gray-500 uppercase font-bold tracking-wider">Time Slot</div>
                                        <div className="font-mono font-medium text-white">{item.startTime} - {item.endTime}</div>
                                    </div>
                                </div>
                            </div>

                            <button
                                onClick={() => handleMarkAttendance(item)}
                                disabled={item.status === 'Upcoming'}
                                className={`w-full py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${item.status === 'Ongoing'
                                    ? 'bg-green-600 text-white hover:bg-green-700 shadow-lg shadow-green-500/30'
                                    : item.status === 'Submitted'
                                        ? 'bg-purple-600 text-white hover:bg-purple-700 shadow-lg shadow-purple-500/30'
                                        : item.status === 'Expired'
                                            ? 'bg-orange-600 text-white hover:bg-orange-700 shadow-lg shadow-orange-500/30' // New style for Expired but actionable
                                            : 'bg-gray-700 text-gray-500 cursor-not-allowed border border-gray-600'
                                    }`}
                            >
                                {item.status === 'Ongoing' && <><PlayCircle size={18} /> Mark Attendance</>}
                                {item.status === 'Submitted' && <><CheckCircle size={18} /> View / Edit</>}
                                {item.status === 'Upcoming' && <><Clock size={18} /> Starts Soon</>}
                                {item.status === 'Expired' && <><Shield size={18} /> Mark Late</>}
                            </button>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default FacultyAttendance;

