import { useNavigate, Link } from 'react-router-dom';
import { useState, useEffect } from 'react';
import axios from 'axios';
import { LayoutDashboard, Users, LogOut, FileText, Shield } from 'lucide-react';
import SecuritySection from '../components/SecuritySection';
import ProfileSection from '../components/ProfileSection';
import StatCard from '../components/StatCard';
import { Calendar, Users as UsersIcon, AlertCircle, CheckCircle } from 'lucide-react';

const FacultyDashboard = () => {
    const navigate = useNavigate();
    const [activeTab, setActiveTab] = useState('overview');
    const [greeting, setGreeting] = useState('');
    const [user, setUser] = useState(null);

    useEffect(() => {
        const hour = new Date().getHours();
        if (hour < 12) setGreeting('Good Morning');
        else if (hour < 18) setGreeting('Good Afternoon');
        else setGreeting('Good Evening');

        const fetchUser = async () => {
            try {
                const token = localStorage.getItem('token');
                const res = await axios.get('http://localhost:5000/api/users/me', {
                    headers: { Authorization: `Bearer ${token}` }
                });
                setUser(res.data);
            } catch (err) {
                console.error('Error fetching user:', err);
            }
        };
        fetchUser();
    }, []);

    const [stats, setStats] = useState({
        pending: 0,
        delayed: 0,
        reviewed: 0,
        totalHandled: 0
    });

    const [students, setStudents] = useState([]);
    const [mentoredStudents, setMentoredStudents] = useState([]);

    useEffect(() => {
        const fetchStats = async () => {
            try {
                const token = localStorage.getItem('token');
                const res = await axios.get('http://localhost:5000/api/requests/stats/faculty', {
                    headers: { Authorization: `Bearer ${token}` }
                });
                setStats(res.data);
            } catch (err) {
                console.error('Error fetching stats:', err);
            }
        };
        fetchStats();
    }, []);

    useEffect(() => {
        if (activeTab === 'students') {
            const fetchStudents = async () => {
                try {
                    const token = localStorage.getItem('token');
                    const res = await axios.get('http://localhost:5000/api/users/faculty/students', {
                        headers: { Authorization: `Bearer ${token}` }
                    });
                    setStudents(res.data);
                } catch (err) {
                    console.error('Error fetching students:', err);
                }
            };
            fetchStudents();
        } else if (activeTab === 'mentored') {
            const fetchMentoredStudents = async () => {
                try {
                    const token = localStorage.getItem('token');
                    const res = await axios.get('http://localhost:5000/api/mentors/faculty', {
                        headers: { Authorization: `Bearer ${token}` }
                    });
                    setMentoredStudents(res.data);
                } catch (err) {
                    console.error('Error fetching mentored students:', err);
                }
            };
            fetchMentoredStudents();
        }
    }, [activeTab]);

    const handleLogout = () => {
        localStorage.removeItem('token');
        localStorage.removeItem('role');
        navigate('/login');
    };

    return (
        <div style={{ padding: '2rem' }}>
            <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <h1 className="text-3xl font-bold">{greeting}, {user?.name || 'Professor'}</h1>
                <div className="flex gap-4">
                    <button
                        onClick={() => setActiveTab('overview')}
                        className={`px-4 py-2 rounded-lg font-medium transition-colors flex items-center ${activeTab === 'overview'
                            ? 'bg-blue-600 text-white shadow-sm'
                            : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                            }`}
                    >
                        <LayoutDashboard size={18} className="mr-2" />
                        Overview
                    </button>
                    <button
                        onClick={() => setActiveTab('students')}
                        className={`px-4 py-2 rounded-lg font-medium transition-colors flex items-center ${activeTab === 'students'
                            ? 'bg-blue-600 text-white shadow-sm'
                            : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                            }`}
                    >
                        <Users size={18} className="mr-2" />
                        All Students
                    </button>
                    <button
                        onClick={() => setActiveTab('mentored')}
                        className={`px-4 py-2 rounded-lg font-medium transition-colors flex items-center ${activeTab === 'mentored'
                            ? 'bg-purple-600 text-white shadow-sm'
                            : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                            }`}
                    >
                        <Users size={18} className="mr-2" />
                        My Mentees
                    </button>
                    <button
                        onClick={() => setActiveTab('security')}
                        className="hidden"
                    >
                        <Shield size={18} className="mr-2" />
                        Security
                    </button>
                    <button
                        onClick={() => setActiveTab('profile')}
                        className={`px-4 py-2 rounded-lg font-medium transition-colors flex items-center ${activeTab === 'profile'
                            ? 'bg-blue-600 text-white shadow-sm'
                            : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                            }`}
                    >
                        <Users size={18} className="mr-2" />
                        Profile
                    </button>
                    <button onClick={handleLogout} className="bg-red-500 text-white px-4 py-2 rounded hover:bg-red-600 transition-colors ml-4 flex items-center">
                        <LogOut size={18} className="mr-2" />
                        Logout
                    </button>
                </div>
            </header>

            {activeTab === 'overview' && (
                <>
                    {/* Stats Overview */}
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
  <StatCard icon={Calendar} title="Today's Total Lectures" value="5" />
  <StatCard icon={UsersIcon} title="Total Assigned Students" value={students.length} />
  <StatCard icon={AlertCircle} title="Pending Academic Requests" value={stats.pending} />
  <StatCard icon={CheckCircle} title="Completed Attendance Sessions Today" value="3" />
                        <div className="bg-white p-6 rounded shadow border-l-4 border-yellow-500">
                            <div className="text-gray-500 text-sm font-semibold uppercase tracking-wider">Pending Review</div>
                            <div className="text-3xl font-bold text-gray-800 mt-2">{stats.pending}</div>
                        </div>
                        <div className="bg-white p-6 rounded shadow border-l-4 border-red-500">
                            <div className="text-gray-500 text-sm font-semibold uppercase tracking-wider">Delayed Requests</div>
                            <div className="text-3xl font-bold text-red-600 mt-2">{stats.delayed}</div>
                        </div>
                        <div className="bg-white p-6 rounded shadow border-l-4 border-blue-500">
                            <div className="text-gray-500 text-sm font-semibold uppercase tracking-wider">Reviewed by Me</div>
                            <div className="text-3xl font-bold text-gray-800 mt-2">{stats.reviewed}</div>
                        </div>
                        <div className="bg-white p-6 rounded shadow border-l-4 border-gray-500">
                            <div className="text-gray-500 text-sm font-semibold uppercase tracking-wider">Total Handled</div>
                            <div className="text-3xl font-bold text-gray-800 mt-2">{stats.totalHandled}</div>
                        </div>
                    </div>

                    <div className="text-center mt-12 bg-white p-10 rounded-xl shadow-sm border border-gray-100">
                        <h2 className="text-2xl font-bold text-gray-800 mb-4">Academic Requests</h2>
                        <p className="text-gray-500 mb-6">Review and manage pending student requests.</p>
                        <Link to="/faculty/requests" className="inline-flex items-center px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium">
                            <FileText size={20} className="mr-2" />
                            Review Academic Requests
                        </Link>
                        <Link to="/faculty/attendance" className="inline-flex items-center px-6 py-3 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors font-medium ml-4">
                            <FileText size={20} className="mr-2" />
                            Manage Attendance
                        </Link>
                        <Link to="/faculty/assessments" className="inline-flex items-center px-6 py-3 bg-yellow-600 text-white rounded-lg hover:bg-yellow-700 transition-colors font-medium ml-4">
                            <FileText size={20} className="mr-2" />
                            Assessments
                        </Link>
                    </div>
                </>
            )}

            {activeTab === 'students' && (
                /* Student List Table */
                <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                    <div className="p-6 border-b border-gray-100">
                        <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
                            <Users size={20} className="text-blue-500" />
                            Students (Departmental)
                        </h2>
                        <p className="text-sm text-gray-500 mt-1">
                            Showing students from your department who have submitted requests.
                        </p>
                    </div>
                    <div className="overflow-x-auto">
                        <table className="w-full text-left">
                            <thead className="bg-gray-50 border-b border-gray-100">
                                <tr>
                                    <th className="p-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">#</th>
                                    <th className="p-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Login ID</th>
                                    <th className="p-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Name</th>
                                    <th className="p-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Semester</th>
