import { useState, useEffect } from 'react';
import axios from 'axios';
import RequestTimeline from '../components/RequestTimeline';

const FacultyRequests = () => {
    const [requests, setRequests] = useState([]);
    const [remarksInput, setRemarksInput] = useState({}); // Map requestId -> remark text
    const [message, setMessage] = useState('');
    const [selectedRequestId, setSelectedRequestId] = useState(null);
    const [activeTab, setActiveTab] = useState('pending'); // 'pending' (Active) or 'history' (Archived)

    const fetchRequests = async () => {
        try {
            const token = localStorage.getItem('token');
            const isArchived = activeTab === 'history';

            // Refactored Logic:
            // Active Tab -> /api/requests/all (Defined in getAllRequests)
            // History Tab -> /api/requests/history (Defined in getFacultyReviewedRequests)
            const url = isArchived
                ? 'http://localhost:5000/api/requests/history'
                : 'http://localhost:5000/api/requests/all';

            const res = await axios.get(url, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setRequests(res.data);
        } catch (err) {
            console.error('Error fetching requests:', err);
        }
    };

    useEffect(() => {
        fetchRequests();
    }, [activeTab]);

    const handleRemarkChange = (reqId, value) => {
        setRemarksInput(prev => ({ ...prev, [reqId]: value }));
    };

    const handleAction = async (requestId, status) => {
        const remarks = remarksInput[requestId];
        if (!remarks) {
            setMessage(`Please enter remarks to ${status === 'Faculty Approved' ? 'Approve' : 'Reject'}`);
            return;
        }

        try {
            const token = localStorage.getItem('token');
            await axios.put(`http://localhost:5000/api/requests/${requestId}/status`,
                { status, remarks },
                { headers: { Authorization: `Bearer ${token}` } }
            );
            setMessage(`Request ${status} successfully`);
            fetchRequests(); // Refresh list
        } catch (err) {
            console.error('Error updating status:', err);
            setMessage('Error updating request status');
        }
    };

    const getStatusBadge = (status) => {
        switch (status) {
            case 'Submitted': return 'bg-yellow-100 text-yellow-800';
            case 'Faculty Approved': return 'bg-blue-100 text-blue-800';
            case 'Approved': return 'bg-green-100 text-green-800';
            case 'Rejected': return 'bg-red-100 text-red-800';
            default: return 'bg-gray-100 text-gray-800';
        }
    };

    return (
        <div className="p-6 max-w-6xl mx-auto">
            <h2 className="text-2xl font-bold mb-6">Review Academic Requests</h2>

            {message && <div className="bg-blue-50 text-blue-700 p-4 rounded mb-4">{message}</div>}

            <div className="flex mb-4">
                <button
                    className={`px-4 py-2 font-semibold rounded-t-lg ${activeTab === 'pending' ? 'bg-white text-blue-600 border-t-2 border-blue-600' : 'bg-gray-100 text-gray-600'}`}
                    onClick={() => setActiveTab('pending')}
                >
                    Pending Review
                </button>
                <button
                    className={`px-4 py-2 font-semibold rounded-t-lg ${activeTab === 'history' ? 'bg-white text-blue-600 border-t-2 border-blue-600' : 'bg-gray-100 text-gray-600'}`}
                    onClick={() => setActiveTab('history')}
                >
                    My Reviewed History
                </button>
            </div>

            <div className="bg-white rounded shadow text-gray-900 overflow-hidden">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="bg-gray-50 border-b">
                            <th className="p-4 font-semibold text-gray-600">Request ID</th>
                            <th className="p-4 font-semibold text-gray-600">Student</th>
                            <th className="p-4 font-semibold text-gray-600">Type & Description</th>
                            <th className="p-4 font-semibold text-gray-600">Status</th>
                            <th className="p-4 font-semibold text-gray-600 w-1/3">Action & Remarks</th>
                        </tr>
                    </thead>
                    <tbody>
                        {requests.length === 0 ? (
                            <tr><td colSpan="5" className="p-8 text-center text-gray-500">No requests found.</td></tr>
                        ) : (
                            requests.map((item) => {
                                // Normalize data based on tab
                                const isHistory = activeTab === 'history';
                                const request = isHistory ? item.requestDetails : item;
                                const displayStatus = isHistory ? item.action : item.status;
                                const displayRemarks = isHistory ? item.remarks : item.facultyRemarks;
                                const displayDate = isHistory ? item.actionDate : item.createdAt;

                                return (
                                    <tr key={item.requestId || item.auditId} className="border-b hover:bg-gray-50 transition-colors">
                                        <td className="p-4 align-top font-mono text-sm">
                                            {request.requestId}
                                            <button
                                                onClick={() => setSelectedRequestId(request.requestId)}
                                                className="block mt-2 text-blue-600 hover:text-blue-800 underline text-xs"
                                            >
                                                View Timeline
                                            </button>
                                        </td>
                                        <td className="p-4 align-top">
                                            <div className="font-medium">{request.studentId?.name || 'Unknown'}</div>
                                            <div className="text-sm text-gray-500">{request.studentId?.loginId}</div>
                                            <div className="text-xs text-gray-400 mt-1">
                                                {isHistory ? 'Action Date: ' : 'Submitted: '}
                                                {new Date(displayDate).toLocaleDateString()}
                                            </div>
                                        </td>
                                        <td className="p-4 align-top">
                                            <div className="font-semibold text-gray-800 mb-1">{request.requestType}</div>
                                            <div className="text-sm text-gray-600">{request.description}</div>
                                        </td>
                                        <td className="p-4 align-top">
                                            <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide ${getStatusBadge(displayStatus)}`}>
                                                {displayStatus}
                                            </span>
                                        </td>
                                        <td className="p-4 align-top">
                                            {!isHistory ? (
                                                <div className="space-y-3">
                                                    <textarea
                                                        placeholder="Enter remarks (Mandatory)..."
                                                        className="w-full p-2 border rounded text-sm text-gray-900 bg-white"
                                                        rows="2"
                                                        value={remarksInput[request.requestId] || ''}
                                                        onChange={(e) => handleRemarkChange(request.requestId, e.target.value)}
                                                    ></textarea>
                                                    <div className="flex gap-2">
                                                        <button
                                                            onClick={() => handleAction(request.requestId, 'Faculty Approved')}
                                                            className="px-3 py-1 bg-green-600 text-white rounded text-sm hover:bg-green-700 font-medium flex-1"
                                                        >
                                                            Approve
                                                        </button>
                                                        <button
                                                            onClick={() => handleAction(request.requestId, 'Rejected')}
                                                            className="px-3 py-1 bg-red-600 text-white rounded text-sm hover:bg-red-700 font-medium flex-1"
                                                        >
                                                            Reject
                                                        </button>
                                                    </div>
                                                </div>
                                            ) : (
                                                <div className="text-sm">
                                                    <div className="font-semibold text-gray-700">My Remarks:</div>
                                                    <div className="text-gray-600 italic">"{displayRemarks}"</div>
                                                    {request.isFacultyDelayed && (
                                                        <span className="inline-block mt-2 px-2 py-0.5 bg-yellow-100 text-yellow-800 text-xs font-bold rounded border border-yellow-200">
                                                            ⚠ Delayed
                                                        </span>
                                                    )}
                                                </div>
                                            )}
                                        </td>
                                    </tr>
                                );
                            })
                        )}
                    </tbody>
                </table>
            </div>

            {selectedRequestId && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
                    <RequestTimeline
                        requestId={selectedRequestId}
                        onClose={() => setSelectedRequestId(null)}
                    />
                </div>
            )}
        </div>
    );
};

export default FacultyRequests;

import React, { useState, useEffect } from 'react';
import axios from 'axios';

const StudentAttendance = () => {
    const [summary, setSummary] = useState([]);
    const [loading, setLoading] = useState(true);
    const [selectedSubject, setSelectedSubject] = useState(null);
    const [details, setDetails] = useState([]);

    const token = localStorage.getItem('token');

    useEffect(() => {
        fetchSummary();
    }, []);

    const fetchSummary = async () => {
        try {
            const res = await axios.get('http://localhost:5000/api/attendance/student/summary', {
                headers: { Authorization: `Bearer ${token}` }
            });
            setSummary(res.data);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const fetchDetails = async (subjectId) => {
        try {
            const res = await axios.get(`http://localhost:5000/api/attendance/student/subject/${subjectId}`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            setDetails(res.data);
            setSelectedSubject(subjectId);
        } catch (err) {
            console.error(err);
        }
    };

    const getStatusColor = (percentage) => {
        if (percentage >= 75) return 'text-green-600';
        if (percentage >= 60) return 'text-yellow-600';
        return 'text-red-600';
    };

    const getCardBorder = (percentage) => {
        if (percentage >= 75) return 'border-green-500';
        if (percentage >= 60) return 'border-yellow-500';
        return 'border-red-500';
    };

    return (
        <div className="p-6 max-w-7xl mx-auto">
            <h2 className="text-3xl font-bold mb-8 text-white flex items-center gap-3">
                <span>📚</span> My Attendance
            </h2>

            {loading ? (
                <div className="text-white text-center p-8">Loading attendance data...</div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
                    {summary.map((item, index) => (
                        <div
                            key={index}
                            className={`bg-gray-800 p-6 rounded-xl shadow-lg border-l-4 cursor-pointer hover:shadow-2xl transition transform hover:-translate-y-1 ${getCardBorder(item.percentage)}`}
                            onClick={() => fetchDetails(item.subjectId)}
                        >
                            <h3 className="text-xl font-bold mb-1 text-white">{item.subjectName}</h3>
                            <p className="text-gray-400 mb-4 text-sm font-mono">{item.subjectCode}</p>

                            <div className="flex justify-between items-end">
                                <div>
                                    <p className="text-gray-400 text-xs uppercase tracking-wider mb-1">Attendance</p>
                                    <span className={`text-3xl font-bold ${getStatusColor(item.percentage)}`}>
                                        {item.percentage}%
                                    </span>
                                </div>
                                <div className="text-right">
                                    <p className="text-gray-400 text-xs uppercase tracking-wider mb-1">Lectures</p>
                                    <span className="text-white font-medium">
                                        {item.attendedLectures} <span className="text-gray-500">/</span> {item.totalLectures}
                                    </span>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {/* Detailed View Modal/Section */}
            {selectedSubject && (
                <div className="mt-8 bg-gray-800 rounded-xl border border-gray-700 shadow-2xl overflow-hidden animate-fade-in-up">
                    <div className="p-6 border-b border-gray-700 flex justify-between items-center bg-gray-900/50">
                        <h3 className="text-xl font-bold text-white">📅 detailed Report</h3>
                        <button
                            onClick={() => setSelectedSubject(null)}
                            className="text-gray-400 hover:text-white transition flex items-center gap-1"
                        >
                            ✕ Close
                        </button>
                    </div>

                    <div className="overflow-x-auto">
                        <table className="w-full text-left">
                            <thead className="bg-gray-900/50 border-b border-gray-700">
                                <tr>
                                    <th className="p-4 text-gray-400 font-medium">Date</th>
                                    <th className="p-4 text-gray-400 font-medium">Status</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-700">
                                {details.map((d, i) => (
                                    <tr key={i} className="hover:bg-gray-700/50 transition">
                                        <td className="p-4 text-gray-300 font-mono">
                                            {new Date(d.date).toLocaleDateString(undefined, { weekday: 'short', year: 'numeric', month: 'short', day: 'numeric' })}
                                        </td>
                                        <td className="p-4">
                                            <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider border ${d.status === 'Present' ? 'bg-green-900/30 text-green-400 border-green-800' : 'bg-red-900/30 text-red-400 border-red-800'}`}>
                                                {d.status}
                                            </span>
                                        </td>
                                    </tr>
                                ))}
                                {details.length === 0 && (
                                    <tr>
                                        <td colSpan="2" className="p-8 text-center text-gray-500">No attendance records found for this subject.</td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}
        </div>
    );
};

export default StudentAttendance;

