import StatCard from '../components/StatCard';
import SecuritySection from '../components/SecuritySection';
import { Clock, Book, AlertCircle, CheckCircle, LayoutDashboard, Users, LogOut, FileText, Shield, Calendar, Users as UsersIcon } from 'lucide-react';

