                                    ? 'bg-gray-300 text-gray-500 cursor-not-allowed'
                                    : 'bg-indigo-600 text-white hover:bg-indigo-700'
                                    }`}
                            >
                                {aiLoading ? 'Thinking...' : 'Ask AI'}
                            </button>
                        </div>

                        {aiResponse && (
                            <div className="mt-4 p-4 bg-gray-50 rounded-lg border border-gray-200">
                                <h3 className="text-sm font-semibold text-gray-700 mb-2">Response:</h3>
                                <p className="text-gray-800 whitespace-pre-wrap leading-relaxed">
                                    {aiResponse}
                                </p>
                            </div>
                        )}
                    </div>
                    */}                        {/* Statistics Cards */}
                        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8 max-w-6xl mx-auto">
                          <StatCard
                            icon={Clock}
                            title="Attendance Percentage"
                            value={stats.finalApproved + stats.rejected > 0 ? `${Math.round((stats.finalApproved / (stats.finalApproved + stats.rejected)) * 100)}%` : "-"}
                          />
                          <StatCard
                            icon={Book}
                            title="Total Subjects"
                            value={"4"}
                          />
                          <StatCard
                            icon={AlertCircle}
                            title="Pending Academic Requests"
                            value={stats.submitted}
                          />
                          <StatCard
                            icon={CheckCircle}
                            title="Approved Requests"
                            value={stats.facultyApproved}
                          />
                        </div>
                    {/* My Mentor Section */}
                    {mentor && (
                        <div className="max-w-6xl mx-auto mb-8 bg-white p-6 rounded-xl shadow-sm border border-blue-100">
                            <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
                                <span className="p-2 bg-blue-100 rounded-lg text-blue-600">🎓</span>
                                My Assigned Mentor
                            </h2>
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                <div>
                                    <p className="text-sm text-gray-500 uppercase font-semibold">Faculty Name</p>
                                    <p className="text-lg font-medium text-gray-900">{mentor.facultyId?.name}</p>
                                </div>
                                <div>
                                    <p className="text-sm text-gray-500 uppercase font-semibold">Contact Email</p>
                                    <p className="text-lg font-medium text-gray-900">{mentor.facultyId?.email}</p>
                                </div>
                                <div>
                                    <p className="text-sm text-gray-500 uppercase font-semibold">Department</p>
                                    <p className="text-lg font-medium text-gray-900">{mentor.department}</p>
                                </div>
                            </div>
                            <div className="mt-4 pt-4 border-t border-gray-100 flex justify-end">
                                <Link
                                    to="/student/chat"
                                    className="inline-flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors font-medium shadow-sm"
                                >
                                    <span className="mr-2">💬</span> Chat with Mentor
                                </Link>
                            </div>

                        </div>
                    )}

                    <div className="space-y-4 text-center">
                        <div>
                            <Link to="/student/requests" className="text-blue-600 hover:text-blue-800 text-lg underline mr-4">
                                View & Submit Academic Requests
                            </Link>
                            <Link to="/student/attendance" className="text-green-600 hover:text-green-800 text-lg underline mr-4">
                                View My Attendance
                            </Link>
                            <Link to="/student/marks" className="text-yellow-600 hover:text-yellow-800 text-lg underline">
                                View My Marks
                            </Link>
                        </div>
                    </div>
                </>
            )}

            <div className="text-center mt-8">
                <button
                    onClick={handleLogout}
                    className="bg-red-500 text-white px-4 py-2 rounded hover:bg-red-600 transition-colors"
                >
                    Logout
                </button>
            </div>
        </div>
    );
};

export default StudentDashboard;
